--- 获取角色基础信息
function LxRoleHandler:GetRoleInfoReq(roleId)
    ---@type LxLoginModule
    local loginMod = ModuleCenter.Login
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GetRoleInfoReq)
    proto.roleId = roleId or loginMod:GetRoleId()
    SendMessage(LxProtoIds.GetRoleInfoReq, proto)
end

--- 查看玩家信息请求
function LxRoleHandler:RoleInfoShowReq(roleId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleInfoShowReq)
    proto.roleId = roleId
    SendMessage(LxProtoIds.RoleInfoShowReq, proto)
end

function LxRoleHandler:RandomRoleNameReq(language, sex)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RandomRoleNameReq)
    if language then
        proto.language = language
    end
    proto.sex = sex
    SendMessage(LxProtoIds.RandomRoleNameReq, proto)
end

function LxRoleHandler:RoleRenameReq(name, sex)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleRenameReq)
    proto.newName = name
    --- 性别,0-女,1-男
    proto.sex = sex
    SendMessage(LxProtoIds.RoleRenameReq, proto)
end
--- 改变性别
function LxRoleHandler:RoleChangeSexReq(sex)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleRenameReq)
    proto.sex = sex
    SendMessage(LxProtoIds.RoleRenameReq, proto)
end
