---refId通过配置找到对应的type
function LxRoleHandler:SetRoleCardWearReq(refId)
    if not refId then return end

    local ref = GameTable.RoleCardRef[refId]
    if not ref then return end

    self:RoleCardWearReq(ref.type, refId)
end

--- 请求穿戴装扮
function LxRoleHandler:RoleCardWearReq(type,refId)
    if not type then
        local ref = GameTable.RoleCardRef[refId]
        type = ref and ref.type
    end
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleCardWearReq)
    proto.type = type
    proto.refId = refId
    SendMessage(LxProtoIds.RoleCardWearReq, proto)
end

