function LxRoleHandler:RoleUpdateSignatureReq(signature)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleUpdateSignatureReq)
    proto.signature = signature
    SendMessage(LxProtoIds.RoleUpdateSignatureReq, proto)
end

--- 更新指引(登陆时服务端主动推送Resp协议)
function LxRoleHandler:GuideChangeReq(guideRefId, guideIds)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.GuideChangeReq)
    --- 最新指引 GuideConditionRef refId
    proto.trip = guideRefId

    for k,v in ipairs(guideIds) do
        proto.guide:append(v)
    end
    --ModuleCenter.Guide:AddFinishedGuideId(guideRefId)
    --for i, v in pairs(guideIds) do
    --    if(v > 0)then
    --        ModuleCenter.Guide:AddFinishedGuideId(v)
    --    end
    --end
    SendMessage(LxProtoIds.GuideChangeReq, proto)
end

