--- 玩家剧情进度
function LxRoleHandler:SceneSystemLookReq(type, refId)

    local pb = LxProtoHelper.CreateProto(LxProtoIds.SceneSystemLookReq)
    for i, v in pairs(refId) do
        pb.storyNewbies:append(v)
    end
    pb.sceneId = refId[1] or 0
    pb.type = type
    SendMessage(LxProtoIds.SceneSystemLookReq, pb)
end

