--- s2c
function LxRoleHandler:OnGetRoleInfoResp(pb)
    CtrlCenter.Role:SetRoleInfo(pb)
end

function LxRoleHandler:OnRoleInfoShowResp(pb)
    local commonModule = ModuleCenter.Common
    local heroModule = ModuleCenter.Hero
    local showHeros = {}
    if pb.showHero then
        for i,v in ipairs(pb.showHero) do
            table.insert(showHeros,heroModule:NewHero(v))
        end
    end
    FireEvent(EventNames.ROLE_INFO_SHOW_RETURN, {
        roleSimpleInfo = commonModule:NewRoleSimpleInfo(pb.roleSimpleInfo),
        playerPanel = commonModule:NewRoleAttrPanel(pb.attrPanel),
        lookRoleInfo = pb.roleSimpleInfo,
        showHeros = showHeros,
    })
end

function LxRoleHandler:OnRandomRoleNameResp(pb)

end

function LxRoleHandler:OnRoleRenameResp(pb)
    CtrlCenter.Role:OnRenameOk()
    --CtrlCenter.Guide:DoTrigger(6,1)
    CtrlCenter.Guide:DoTrigger()
end

function LxRoleHandler:OnRoleCardResp(pb)
    self:DisposeRoleCardObj(pb.roleCardObj)
end

function LxRoleHandler:DisposeRoleCardObj(pb)
    ---@type LxRoleCardObj
    local obj = ModuleCenter.Role:GetRoleCardObj(pb)
    ModuleCenter.Role:SetRoleCardInfos(obj.roleCardInfos)
end

function LxRoleHandler:OnRoleCardUpdateResp(pb)
    ModuleCenter.Role:SetRoleCardInfos(pb.roleCardInfos)
end

