--玩家指引进度(登陆时服务端主动推送Resp协议)
function LxRoleHandler:OnGuideInfoResp(pb)
    local trips = pb.trips
    local guide = pb.guide
    local keepTrips = pb.keepTrips
    CtrlCenter.Guide:OnGuideInfoResp(trips, guide, keepTrips)
end

function LxRoleHandler:OnGuideChangeResp(pb)
    --- 最新指引refId,0表示未经历任何指引
    local trip = pb.trip
    local guide = pb.guide
    ModuleCenter.Guide:AddFinishedGuideId(trip)
    ModuleCenter.Guide:SetProgress(guide)
    CtrlCenter.Guide:OnGuideChange(trip, guide)
end

function LxRoleHandler:OnSettingResp(pb)
    --- 最聊天限制,无值不限制.下标从0开始,每一位表示一个系统,0-无限制,1-限制
    local chatForbid = pb.chatForbid
    local worldLevel = pb.worldLevel
    ModuleCenter.Role:SetWorldLevel(worldLevel)
    for key,value in ipairs(pb.chatSet) do
        ModuleCenter.Chat:SetChatSetting(value.key,value.value)
    end
end

function LxRoleHandler:OnShieldOtherResp(pb)
    --- 最新指引refId,0表示未经历任何指引
    local roleId = pb.roleId
    local type = pb.type
end

function LxRoleHandler:OnMutableAttrResp(pb)
    if pb:HasField("power") then
        CtrlCenter.Role:OnRolePowerChange(tonumber(pb.power))
    end
    if pb:HasField("maxPower") then
        CtrlCenter.Role:OnRoleMaxPowerChange(tonumber(pb.maxPower))
    end
end

function LxRoleHandler:OnCharacterActivateResp(pb)
end

function LxRoleHandler:OnExplorerUpLevelResp(pb)
    FireEvent(EventNames.ROLE_EXPLORER_LEVEL)
    ShowSysMsg(I18nText(7314))
end

--- RoleDataSyncPb协议
function LxRoleHandler:OnRoleDataResp(pb)
    if pb.itemBagObj then
        local itemBagObj = pb.itemBagObj
        local changeList, removeIds = ModuleCenter.Item:SetItems(itemBagObj.items or {})
        FireEvent(EventNames.ITEM_CHANGED, changeList, removeIds)
    end
    --- 居民数据
    if pb:HasField("peopleDataObj") then
        local peopleDataObj = pb.peopleDataObj
        ModuleCenter.People:SetPeopleData(peopleDataObj)
        CtrlCenter.People:CheckHeartUp()
        FireEvent(EventNames.PEOPLE_INFO_CHANGE)
        CtrlCenter.City:NewPeoples(ModuleCenter.People:GetPeopleNum())
    end
    if pb:HasField("heroBagObj") then
        ModuleCenter.Hero:SetHeroBagObj(pb.heroBagObj)
        FireEvent(EventNames.HERO_INFO_CHANGE)
    end
    if pb.heroCallDataObj then
        local heroCallDataObj = pb.heroCallDataObj
        ModuleCenter.HeroCall:SetHeroCallInfos(heroCallDataObj.callInfoList or {})
        FireEvent(EventNames.HEROCALL_CALLRESULT)
    end
    if pb:HasField("buildingDataObj") then
        local buildingDataObj = pb.buildingDataObj
        ModuleCenter.Building:SetBuildingData(buildingDataObj)
        FireEvent(EventNames.REFRESH_BUILD_INFO)
    end

    if pb:HasField("resDataObj") then
        local resDataObj = pb.resDataObj
        ModuleCenter.Building:SetProduceResData(resDataObj)
        FireEvent(EventNames.REFRESH_BUILD_RESPRODUCE)
    end

    if pb:HasField("soldierBagObj") then
        local soldierBagObj = pb.soldierBagObj
        ModuleCenter.Soldier:SetSoldierData(soldierBagObj)
        FireEvent(EventNames.REFRESH_SOLDIER_COUNT)
    end
    if(pb:HasField("cityDataObj"))then
        ModuleCenter.Role:SetCityMonster(pb.cityDataObj)
        CtrlCenter.City:RefreshMonster()
    end
    if(pb:HasField("arenaDataObj"))then
        ModuleCenter.Arena:SetArenaData(pb.arenaDataObj)
    end
    if (pb:HasField("dunDailyDataObj")) then
        ModuleCenter.DailyMain:SetDailyDunData(pb.dunDailyDataObj);
    end

    if (pb:HasField("marchAssistDataObj")) then
        ModuleCenter.World:SetMarchAssistData(pb.marchAssistDataObj)
        FireEvent(EventNames.REFRESH_EMBASSYASSISTLIST)
    end


    if pb:HasField("equipBagObj") then
        local LxEquipModule = ModuleCenter.Equip
        for k, v in ipairs(pb.equipBagObj.equips) do
            LxEquipModule:SetBagData(v)
        end
    end

----[[    if pb:HasField("clothesBagObj") then
--        ModuleCenter.Clothes:InitClothesInfo(pb.clothesBagObj)
--        FireEvent(EventNames.CLOTHES_UPDATE)
--    end]]
--
--    if pb:HasField("towerDataObj") then
--        local towerDataObj = pb.towerDataObj
--        ModuleCenter.Tower:SetTowerInfo(towerDataObj)
--        FireEvent(EventNames.TOWER_INFO_UPDATE)
--    end
--    if pb.crestBagObj then
--        local crestBagObj = pb.crestBagObj
--        ModuleCenter.Crest:SetCrestBag(crestBagObj)
--        FireEvent(EventNames.CREST_BAG_UPDATE)
--    end
    if pb:HasField("questObj") then
        if #pb.questObj.questList > 0 then
            for i,v in ipairs(pb.questObj.questList) do
                ModuleCenter.Quest:AddQuest(v)
            end
            ModuleCenter.Quest:OnQuestPrint()
            FireEvent(EventNames.QUEST_UPDATE)
        end
        if #pb.questObj.plots > 0 then
            for i,v in ipairs(pb.questObj.plots) do
                ModuleCenter.Quest:AddChapterId(v)
            end
            FireEvent(EventNames.QUEST_UPDATE)
        end
        if #pb.questObj.peopleTimes > 0 then
            for i,v in ipairs(pb.questObj.peopleTimes) do
                ModuleCenter.Quest:SetPeopleTimes(v)
            end
            FireEvent(EventNames.QUEST_UPDATE)
        end
        if #pb.questObj.timeLimits > 0 then
            for i,v in ipairs(pb.questObj.timeLimits) do
                ModuleCenter.Quest:AddTimeLimitTask(v)
            end
            FireEvent(EventNames.QUEST_UPDATE)
        end
    end
--
    if pb.heroSkinBagObj then
        ModuleCenter.HeroSkin:SetHeroSkinBagObj(pb.heroSkinBagObj)
    end

    if pb:HasField("roleCardObj") then
        ModuleCenter.Role:SetRoleCardInfos(pb.roleCardObj.roleCardInfos)
        FireEvent(EventNames.ROLE_CHANGE_WEAR)
    end

    if pb:HasField("instanceDataObj") then
        local completeMission = ModuleCenter.FightIdle:GetCompleteMission()
        ModuleCenter.FightIdle:SetInitInstanceData(pb.instanceDataObj)
        FireEvent(EventNames.FightIdle_INFO_CHANGE)
        if completeMission and completeMission ~= ModuleCenter.FightIdle:GetCompleteMission() then
            FireEvent(EventNames.FightIdle_MISSION_CHANGE)
        end
    end

    if pb:HasField("marchBagObj") then
        ModuleCenter.World:SetMarchBagData(pb.marchBagObj)
    end
    if(pb:HasField("vipBagObj"))then
        ModuleCenter.Vip:SetVipBagObj(pb.vipBagObj)
    end

    if(pb:HasField("monthlyCardBagObj"))then
        ModuleCenter.MonthCard:SetCardBagObj(pb.monthlyCardBagObj)
        FireEvent(EventNames.REFRESH_MONTHCARD)
    end

    if(pb:HasField("buffDataObj"))then
        ModuleCenter.Buff:SetBuffListPb(pb.buffDataObj)
        FireEvent(EventNames.ROLE_BUFF_UPDATE)
    end

    if(pb:HasField("worldRoleMapData"))then
        ModuleCenter.World:SetFavoritesPbList(pb.worldRoleMapData)
    end

    if pb:HasField("scienceDataObj") then
        ModuleCenter.Science:SetScienceDataList(pb.scienceDataObj.sciences)
    end
    if pb:HasField("watchTowerDataObj") then
        ModuleCenter.WatchTower:SetInfo(pb.watchTowerDataObj)
    end
end

-- 在线跨天,前端可依据此标志重置部分系统的每日次数显示
function LxRoleHandler:OnCrossDayResp(pb)
    local serverTime = tonumber(pb.serverTime)
    local rawOffset = pb.rawOffset
    --MgrCenter.NetworkMgr:SetServerTime(tostring(pb.serverTime))
    ModuleCenter.Login:SetServerTime(serverTime, rawOffset)
    ModuleCenter.Guild:SetGuildCoinNum(0) --跨天设置盟币为0
end


