function LxRoleHandler:RoleUpdateHeroDisplayReq(displays)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.RoleUpdateHeroDisplayReq)
    for _, v in ipairs(displays) do
        table.insert(proto.displays, v.id)
    end
    SendMessage(LxProtoIds.RoleUpdateHeroDisplayReq, proto)
end
function LxRoleHandler:OnRoleUpdateHeroDisplayResp(pb)
    ModuleCenter.Role:SetDisplays(pb)
    FireEvent(EventNames.ROLE_CHANGE_SHOW_HERO)
end

function LxRoleHandler:OnFireOnetimeEventReq(eventId)
    local ids = ModuleCenter.Role._fireOneTimeEventIds
    if not ids then
        ids = {}
        ModuleCenter.Role._fireOneTimeEventIds = ids
    end
    ids[eventId] = eventId
    local proto = LxProtoHelper.CreateProto(LxProtoIds.FireOnetimeEventReq)
    proto.eventId = eventId
    SendMessage(LxProtoIds.FireOnetimeEventReq, proto)
end

function LxRoleHandler:OnFireOnetimeEventResp(pb)
    local ids = {}
    for k, v in ipairs(pb.eventIds) do
        ids[v] = v
    end
    ModuleCenter.Role._fireOneTimeEventIds = ids
end

return LxRoleHandler
